type SiteSignatureAnimation = {
  duration: number;
  easing: [number, number, number, number];
};

export type SiteSignaturePathStroke = SiteSignatureAnimation & {
  kind: "path";
  d: string;
};

export type SiteSignatureRectStroke = SiteSignatureAnimation & {
  kind: "rect";
  x: number;
  y: number;
  width: number;
  height: number;
  rx?: number;
  transform?: string;
};

export type SiteSignatureStroke =
  | SiteSignaturePathStroke
  | SiteSignatureRectStroke;

export type SiteSignatureConfig = {
  viewBox: string;
  width: number;
  strokeWidth: number;
  baseOpacity: number;
  animationOpacity: number;
  pathStagger: number;
  /** Total duration for the single continuous pathLength draw (seconds). */
  totalDrawDuration: number;
  /** Stroke width of the mask path used to reveal the signature (viewBox units). */
  maskStrokeWidth: number;
  strokes: SiteSignatureStroke[];
};

